 84→    const handleClickNotif = handleCLickContent(navigate);
 85→    const handleClickOpinionNotif = handleClickOpinion(navigate);
 86→    const mutationReadNotif = useReadNotificationMutation(session);
 87→
 88→    const handleReadNotif = async(e, notification) => {
 89→        e.stopPropagation();
 90→        const source = notification?.source || 'journal';
 91→        mutationReadNotif.mutate({notifId: notification.id, source})
 92→
 93→        if(source === 'opinion'){
 94→            handleClickOpinionNotif(e, notification?.opinions?.id, notification?.opinions?.user_id)
 95→        } else {
 96→            const parsedContent = ParseContent(notification?.journals?.content);
 97→            handleClickNotif(
 98→                e,
 99→                notification?.journals?.content,
100→                parsedContent.wholeText,
101→                notification?.journals?.title,
102→                notification?.journals?.users.id,
103→                notification?.journals?.users?.name,
104→                notification?.journals?.users?.image_url,
105→                notification?.journals?.created_at,
106→                notification?.journal_id,
107→                notification?.hasLiked,
108→                notification?.journals?.comments[0].count,
109→                notification?.hasBookMarked,
110→                notification?.journals?.likes[0].count,
111→                notification?.journals?.bookmarks[0].count,
112→                notification?.journals?.users?.badge,
113→            )
114→        }
115→    }
116→
117→    const {data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage} = useInfiniteQuery({
118→        queryKey: ['getNotifications', session?.access_token],
119→        queryFn: ({pageParam = null, queryKey}) => getNotifications(queryKey[1], pageParam, 5),
120→        getNextPageParam: (lastpage) =>{
121→            if(lastpage?.hasMore){
122→                const lastNotification = lastpage?.data[lastpage?.data.length - 1];
123→                return new Date(lastNotification.created_at).toISOString();
124→
125→            }
126→            return undefined;
127→        },
128→        enabled: !!session?.access_token,
129→        refetchOnWindowFocus: false
130→    })
131→
132→    useEffect(() =>{
133→        if(scrollToTop.current && !isLoading){
134→            scrollToTop.current.scrollIntoView({behavior: 'smooth'});
135→        }
136→    }, [isLoading])
137→
138→    useEffect(() =>{
139→        if(hasNextPage && !isFetchingNextPage && inView){
140→            // console.log(hasNextPage)
141→            fetchNextPage();
142→        }
143→    }, [hasNextPage, isFetchingNextPage, inView, fetchNextPage])
144→
145→    const notifications = data?.pages?.flatMap((page) => page?.data) || [];
146→
147→    useEffect(() =>{
148→        const handleClickOutside = (e) =>{
149→            if(modalRef.current && !modalRef.current.contains(e.target)){
150→                setSettingsId(null);
151→                // console.log('close')
152→            }
153→        }
154→
155→        document.addEventListener('click', handleClickOutside);
156→        return () =>{
157→            document.removeEventListener('click', handleClickOutside)
158→        }
159→    }, [])
160→
161→     useEffect(() =>{
162→         console.log(data)
163→    }, [data])
164→
165→    const handleClickSettings = (e, notifId) =>{
166→        e.stopPropagation();
167→        // console.log(notifId)
168→        setSettingsId(settingsId === notifId ? null : notifId);
169→    }
170→
171→    const mutationRespondConstellation = useRespondConstellationMutation(session);
172→    const mutationDeleteNotif  = useUserDeleteNotificationMutation(session);
173→
174→    const handleClickDeleteNotification = async(e, notifId, source) =>{
175→        e.stopPropagation();
176→        try {
177→           const message = mutationDeleteNotif.mutateAsync({notifId, source});
178→            if(message){
179→                // console.log(message)
180→            }
181→        } catch (error) {
182→            console.error('error while deleting notification:', error)
183→        }
184→    }
185→
186→    if(notifications.length === 0 && !isLoading){
187→        return(
188→            <div className='notification-loading-container'>
189→                No notifications availabe
190→            </div>
191→        )
192→    }
193→
194→    if(isLoading){
195→        return(
196→            <div className="notification-loading-container">
197→                <MoonLoader size={25} color="var(--loader-color)" loading={isLoading}/>
198→            </div>
199→        )
200→    }
201→
202→    return(
203→        <>
204→        <div ref={scrollToTop}/>
205→        <div className="notifications-container">
206→            {notifications?.map((notification) => {
207→                const isOpinion = notification?.source === 'opinion';
208→                const displayType = isOpinion ? 'opinion_reply' : notification?.type;
209→                const parsedContent = !isOpinion ? ParseContent(notification?.journals?.content) : null;
210→
211→                return(
212→                <div key={`${notification.source}-${notification.id}`} className={notification?.read ? "notification-cards" : "notification-cards-unread"}>
213→
214→                    <div className="notification-cards-child-container">
215→
216→                        <div className="notification-icon-container">
217→                            {iconArray.map((icon, index) => (
218→                                <div className="notification-icon" key={index}>
219→                                    {icon.type === displayType ? icon.icon : null}
220→                                </div>
221→                            ))}
222→                        </div>
223→
224→                        <div className="notification-contents-container">
225→
226→                            <div className="notification-sender-user-metadata">
227→                                <div className="notification-sender-user-metadata-child">
228→                                    <div className={`notif-sender-profilepic-container ${notification?.users?.badge === 'legend' ? 'notif-avatar-ring-legend' : notification?.users?.badge === 'og' ? 'notif-avatar-ring-og' : ''}`}>
229→                                        <img loading="lazy" className="notif-sender-profilepic" src={notification?.users?.image_url || '/assets/profile.jpg'} alt="notificataion sender profile picture" />
230→                                    </div>
231→
232→                                    <div className="notif-sender-name-container">
233→                                        <p className="notif-sender-name">{notification?.users?.name}</p>
234→                                        <VerifiedBadge badge={notification?.users?.badge} size={14} />
235→                                        <p className="notif-type">{FormatNotificationType(displayType)}</p>
236→                                    </div>
237→
238→                                    <div className="notification-date-container">
239→                                        <p className="notification-date">{formatPostDate(notification?.created_at)}</p>
240→                                    </div>
241→                                </div>
242→                                <div className="notification-settings">
243→                                    {settingsId === notification.id && (
244→                                        <AnimatePresence>
245→                                        <motion.div
246→                                        initial={{opacity: 0, scale: 0}}
247→                                        animate={{opacity: 1, scale: 1, transition:{type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
248→                                        exit={{ opacity: 0, scale: 0,
249→                                            transition: {
250→                                            duration: 0.2,
251→                                            ease: "easeOut"
252→                                            }
253→                                        }}
254→                                        ref={modalRef}
255→                                        className="settings-container">
256→
257→                                            <div onClick={(e) => handleClickDeleteNotification(e, notification?.id, notification?.source)} className="delete-notification">
258→                                                <svg xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
259→                                                    <path d="M10 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
260→                                                    <path d="M14 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
