  1→import { useState, useRef, useCallback, useMemo, useEffect } from 'react';
  2→import { userHomeCoords, MAX_UNIVERSE_ZOOM, MIN_UNIVERSE_ZOOM } from '../utils/starUtils';
  3→
  4→const useUniverseCamera = (userId, hasOwnPosts, isStarDragging) => {
  5→    const stageRef = useRef(null);
  6→    const dragStartRef = useRef(null);
  7→    const lastPinchDist = useRef(null);
  8→    const isPinching = useRef(false);
  9→    const hasAdjustedZoom = useRef(false);
 10→
 11→    // Flight state
 12→    const isFlying = useRef(false);
 13→    const flyAnimRef = useRef(null);
 14→    const cameraRef = useRef(null);
 15→    const zoomRef = useRef(null);
 16→
 17→    const [stageSize, setStageSize] = useState({
 18→        width: window.innerWidth,
 19→        height: window.innerHeight,
 20→    });
 21→
 22→    const initialCamera = useMemo(() => {
 23→        if (!userId) return { x: 0, y: 0 };
 24→        return userHomeCoords(userId);
 25→    }, [userId]);
 26→
 27→    // Always enter Universe at maximum zoom-out.
 28→    const initialZoom = useMemo(() => MIN_UNIVERSE_ZOOM, []);
 29→
 30→    const [camera, setCamera] = useState(initialCamera);
 31→    const [zoom, setZoom] = useState(initialZoom);
 32→    const [isDragging, setIsDragging] = useState(false);
 33→
 34→    // Keep refs in sync with state so flyTo reads fresh values without deps
 35→    cameraRef.current = camera;
 36→    zoomRef.current = zoom;
 37→
 38→    // If logged-in user has no posts, center camera while keeping max zoom-out.
 39→    useEffect(() => {
 40→        if (hasAdjustedZoom.current) return;
 41→        if (hasOwnPosts === null) return; // still loading
 42→        if (!userId) return;
 43→        if (!hasOwnPosts) {
 44→            hasAdjustedZoom.current = true;
 45→            setCamera({ x: 0, y: 0 });
 46→            setZoom(MIN_UNIVERSE_ZOOM);
 47→        } else {
 48→            hasAdjustedZoom.current = true;
 49→        }
 50→    }, [hasOwnPosts, userId]);
 51→
 52→    // Resize
 53→    useEffect(() => {
 54→        const onResize = () => setStageSize({ width: window.innerWidth, height: window.innerHeight });
 55→        window.addEventListener('resize', onResize);
 56→        return () => window.removeEventListener('resize', onResize);
 57→    }, []);
 58→
 59→    // Cleanup flight on unmount
 60→    useEffect(() => {
 61→        return () => {
 62→            if (flyAnimRef.current) {
 63→                cancelAnimationFrame(flyAnimRef.current);
 64→                flyAnimRef.current = null;
 65→            }
 66→            isFlying.current = false;
 67→        };
 68→    }, []);
 69→
 70→    // Center world coords (for display)
 71→    const centerWorld = useMemo(() => ({
 72→        x: Math.round(camera.x),
 73→        y: Math.round(camera.y),
 74→    }), [camera]);
 75→
 76→    // Layer transform helper
 77→    const getLayerProps = useCallback((parallaxFactor) => ({
 78→        x: stageSize.width / 2 - camera.x * parallaxFactor * zoom,
 79→        y: stageSize.height / 2 - camera.y * parallaxFactor * zoom,
 80→        scaleX: zoom,
 81→        scaleY: zoom,
 82→    }), [camera, zoom, stageSize]);
 83→
 84→    // Viewport bounds at parallax 1.0 (for data fetching)
 85→    const getViewportBounds = useCallback(() => {
 86→        const halfW = (stageSize.width / 2) / zoom;
 87→        const halfH = (stageSize.height / 2) / zoom;
 88→        const pad = 200 / zoom;
 89→        return {
 90→            minX: camera.x - halfW - pad,
 91→            maxX: camera.x + halfW + pad,
 92→            minY: camera.y - halfH - pad,
 93→            maxY: camera.y + halfH + pad,
 94→        };
 95→    }, [camera, zoom, stageSize]);
 96→
 97→    // --- Drag handling (Stage is NOT draggable) ---
 98→    const handleMouseDown = useCallback((e) => {
 99→        if (isFlying.current) return;
100→        if (isStarDragging?.current) return;
101→        // Only left button for mouse
102→        if (e.evt.button !== undefined && e.evt.button !== 0) return;
103→        dragStartRef.current = {
104→            pointerX: e.evt.clientX ?? e.evt.touches?.[0]?.clientX,
105→            pointerY: e.evt.clientY ?? e.evt.touches?.[0]?.clientY,
106→            camX: camera.x,
107→            camY: camera.y,
108→        };
109→        setIsDragging(true);
110→    }, [camera]);
111→
112→    const handleMouseMove = useCallback((e) => {
113→        if (!dragStartRef.current) return;
114→        if (isPinching.current) return;
115→        if (isStarDragging?.current) return;
116→        const px = e.evt.clientX ?? e.evt.touches?.[0]?.clientX;
117→        const py = e.evt.clientY ?? e.evt.touches?.[0]?.clientY;
118→        if (px == null || py == null) return;
119→        const dx = (px - dragStartRef.current.pointerX) / zoom;
120→        const dy = (py - dragStartRef.current.pointerY) / zoom;
121→        setCamera({
122→            x: dragStartRef.current.camX - dx,
123→            y: dragStartRef.current.camY - dy,
124→        });
125→    }, [zoom]);
126→
127→    const handleMouseUp = useCallback(() => {
128→        dragStartRef.current = null;
129→        setIsDragging(false);
130→        isPinching.current = false;
131→        lastPinchDist.current = null;
132→    }, []);
133→
134→    // --- Wheel zoom ---
135→    const handleWheel = useCallback((e) => {
136→        e.evt.preventDefault();
137→        if (isFlying.current) return;
138→
139→        const stage = stageRef.current;
140→        if (!stage) return;
141→
142→        const pointer = stage.getPointerPosition();
143→        if (!pointer) return;
144→
145→        const screenCenterX = stageSize.width / 2;
146→        const screenCenterY = stageSize.height / 2;
147→
148→        const scaleBy = 1.08;
149→        const direction = e.evt.deltaY > 0 ? -1 : 1;
150→        const oldZoom = zoom;
151→        const newZoom = Math.min(Math.max(
152→            direction > 0 ? oldZoom * scaleBy : oldZoom / scaleBy,
153→            MIN_UNIVERSE_ZOOM
154→        ), MAX_UNIVERSE_ZOOM);
155→
156→        // World point under cursor before zoom
157→        const worldX = camera.x + (pointer.x - screenCenterX) / oldZoom;
158→        const worldY = camera.y + (pointer.y - screenCenterY) / oldZoom;
159→
160→        // Adjust camera so same world point stays under cursor
161→        setCamera({
162→            x: worldX - (pointer.x - screenCenterX) / newZoom,
163→            y: worldY - (pointer.y - screenCenterY) / newZoom,
164→        });
165→        setZoom(newZoom);
166→    }, [zoom, camera, stageSize]);
167→
168→    // --- Touch / Pinch ---
169→    const handleTouchMove = useCallback((e) => {
170→        if (isFlying.current) return;
171→
172→        const touch = e.evt;
173→        if (touch.touches.length === 2) {
174→            // Pinch zoom
175→            isPinching.current = true;
176→            touch.preventDefault();
177→
178→            const t1 = touch.touches[0];
179→            const t2 = touch.touches[1];
180→            const dist = Math.hypot(t2.clientX - t1.clientX, t2.clientY - t1.clientY);
181→
182→            if (lastPinchDist.current === null) {
183→                lastPinchDist.current = dist;
184→                return;
185→            }
186→
187→            const oldZoom = zoom;
188→            const newZoom = Math.min(
189→                Math.max(oldZoom * (dist / lastPinchDist.current), MIN_UNIVERSE_ZOOM),
190→                MAX_UNIVERSE_ZOOM
191→            );
192→            lastPinchDist.current = dist;
193→
194→            const centerX = (t1.clientX + t2.clientX) / 2;
195→            const centerY = (t1.clientY + t2.clientY) / 2;
196→            const screenCenterX = stageSize.width / 2;
197→            const screenCenterY = stageSize.height / 2;
198→
199→            const worldX = camera.x + (centerX - screenCenterX) / oldZoom;
200→            const worldY = camera.y + (centerY - screenCenterY) / oldZoom;
201→
202→            setCamera({
203→                x: worldX - (centerX - screenCenterX) / newZoom,
204→                y: worldY - (centerY - screenCenterY) / newZoom,
205→            });
206→            setZoom(newZoom);
207→        } else if (touch.touches.length === 1 && !isPinching.current) {
208→            // Single finger drag — handled by mouseMove logic
209→            handleMouseMove(e);
210→        }
211→    }, [zoom, camera, stageSize, handleMouseMove]);
212→
213→    const handleTouchEnd = useCallback(() => {
214→        lastPinchDist.current = null;
215→        if (isPinching.current) {
216→            isPinching.current = false;
217→            dragStartRef.current = null;
218→        }
219→    }, []);
220→
221→    const stageEvents = useMemo(() => ({
222→        onMouseDown: handleMouseDown,
223→        onMouseMove: handleMouseMove,
224→        onMouseUp: handleMouseUp,
225→        onWheel: handleWheel,
226→        onTouchStart: handleMouseDown,
227→        onTouchMove: handleTouchMove,
228→        onTouchEnd: handleTouchEnd,
229→    }), [handleMouseDown, handleMouseMove, handleMouseUp, handleWheel, handleTouchMove, handleTouchEnd]);
230→
231→    const jumpTo = useCallback((targetX, targetY) => {
232→        if (flyAnimRef.current) {
233→            cancelAnimationFrame(flyAnimRef.current);
234→            flyAnimRef.current = null;
235→        }
236→        isFlying.current = false;
237→
238→        const nextX = Number.isFinite(targetX) ? targetX : cameraRef.current.x;
239→        const nextY = Number.isFinite(targetY) ? targetY : cameraRef.current.y;
240→        setCamera({ x: nextX, y: nextY });
241→    }, []);
242→
243→    // Google Maps-style fly-to: zoom out → pan → zoom in (parabolic arc)
244→    const flyTo = useCallback((targetX, targetY, targetZoom, onComplete) => {
245→        // Cancel any in-progress flight (without calling old onComplete)
246→        if (flyAnimRef.current) {
247→            cancelAnimationFrame(flyAnimRef.current);
248→            flyAnimRef.current = null;
249→        }
250→
251→        const startX = cameraRef.current.x;
252→        const startY = cameraRef.current.y;
253→        const startZoom = zoomRef.current;
254→        const resolvedTargetZoom = Number.isFinite(targetZoom) ? targetZoom : startZoom;
255→
256→        isFlying.current = true;
257→
258→        // Distance determines how far to zoom out
259→        const dist = Math.hypot(targetX - startX, targetY - startY);
260→
261→        // Fixed cinematic duration
